import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './hooks/useAuth';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import StockList from './pages/StockList';
import Products from './pages/Products';
import ProductDetail from './pages/ProductDetail';
import Movements from './pages/Movements';
import Login from './pages/Login';

function RequireAuth({ children }) {
  const { user } = useAuth();
  return user ? children : <Navigate to="/login" replace />;
}

function AppRoutes() {
  return (
    <div className="app-shell">
      <Sidebar />
      <div className="main-content">
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="/" element={<RequireAuth><Dashboard /></RequireAuth>} />
          <Route path="/stocks" element={<RequireAuth><StockList /></RequireAuth>} />
          <Route path="/produits" element={<RequireAuth><Products /></RequireAuth>} />
          <Route path="/stock/:productId" element={<RequireAuth><ProductDetail /></RequireAuth>} />
          <Route path="/mouvements" element={<RequireAuth><Movements /></RequireAuth>} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Toaster
          position="top-right"
          toastOptions={{
            style: { background: '#1e2537', color: '#e2e8f0', border: '1px solid #2a3352' },
          }}
        />
        <AppRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}
